import React, { useRef, useEffect, FC } from 'react';
import * as THREE from 'three';

/**
 * Props for ThreeScene
 * 
 * @param width           width of the canvas container in px (defaults to container size)
 * @param height          height of the canvas container in px (defaults to container size)
 * @param color1          deep color stop for the shader [r, g, b] (0–1)
 * @param color2          light color stop for the shader [r, g, b] (0–1)
 * @param cardParams      physical material settings for the glass card
 */
export interface ThreeSceneProps {
  width?: number;
  height?: number;
  color1?: [number, number, number];
  color2?: [number, number, number];
  cardParams?: {
    metalness?: number;
    roughness?: number;
    transmission?: number;
    ior?: number;
    thickness?: number;
  };
}

const ThreeScene: FC<ThreeSceneProps> = ({
  width,
  height,
  color1 = [0.1, 0.2, 0.8],
  color2 = [0.8, 0.1, 0.5],
  cardParams = { metalness: 0.1, roughness: 0.2, transmission: 1, ior: 1.5, thickness: 1 },
}) => {
  const mountRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = mountRef.current;
    if (!container) return;

    // Scene, camera, renderer setup
    const scene = new THREE.Scene();
    const { clientWidth, clientHeight } = container;
    const camera = new THREE.PerspectiveCamera(
      75,
      clientWidth / clientHeight,
      0.1,
      1000
    );
    camera.position.z = 5;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(window.devicePixelRatio);
    renderer.setSize(clientWidth, clientHeight);
    container.appendChild(renderer.domElement);

    // Aurora shader background
    const geometry = new THREE.PlaneGeometry(clientWidth / 50, clientHeight / 50);
    const material = new THREE.ShaderMaterial({
      uniforms: {
        u_time: { value: 0 },
        u_resolution: { value: new THREE.Vector2(clientWidth, clientHeight) },
        u_color1: { value: new THREE.Vector3(...color1) },
        u_color2: { value: new THREE.Vector3(...color2) },
      },
      vertexShader: `
        void main() {
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
        }
      `,
      fragmentShader: `
        uniform vec2 u_resolution;
        uniform float u_time;
        uniform vec3 u_color1;
        uniform vec3 u_color2;

        float random(vec2 st) {
          return fract(sin(dot(st, vec2(12.9898,78.233))) * 43758.5453123);
        }

        float noise(vec2 st) {
          vec2 i = floor(st), f = fract(st);
          float a = random(i), b = random(i + vec2(1,0));
          float c = random(i + vec2(0,1)), d = random(i + vec2(1,1));
          vec2 u = f*f*(3.0-2.0*f);
          return mix(a,b,u.x) + (c-a)*u.y*(1.0-u.x) + (d-b)*u.x*u.y;
        }

        void main() {
          vec2 st = gl_FragCoord.xy / u_resolution;
          st.x *= u_resolution.x / u_resolution.y;
          float n = noise(st * 3.0 + u_time * 0.1);
          vec3 color = mix(u_color1, u_color2, n);
          gl_FragColor = vec4(color, 1.0);
        }
      `,
    });

    const background = new THREE.Mesh(geometry, material);
    background.position.z = -10;
    scene.add(background);

    // Glass card mesh
    const cardGeo = new THREE.BoxGeometry(4, 5.5, 0.1);
    const cardMat = new THREE.MeshPhysicalMaterial(cardParams);
    const card = new THREE.Mesh(cardGeo, cardMat);
    scene.add(card);

    // Interaction
    const mouse = new THREE.Vector2();
    const onMouseMove = (ev: MouseEvent) => {
      mouse.x = (ev.clientX / window.innerWidth) * 2 - 1;
      mouse.y = -(ev.clientY / window.innerHeight) * 2 + 1;
    };
    const onResize = () => {
      if (!container) return;
      const w = container.clientWidth;
      const h = container.clientHeight;
      camera.aspect = w / h;
      camera.updateProjectionMatrix();
      renderer.setSize(w, h);
      material.uniforms.u_resolution.value.set(w, h);
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('resize', onResize);

    // Animation loop
    const clock = new THREE.Clock();
    const animate = () => {
      const t = clock.getElapsedTime();
      material.uniforms.u_time.value = t;

      // Parallax card & camera
      card.rotation.x += (mouse.y * 0.2 - card.rotation.x) * 0.05;
      card.rotation.y += (mouse.x * 0.2 - card.rotation.y) * 0.05;
      camera.position.x += (mouse.x * 0.5 - camera.position.x) * 0.05;
      camera.position.y += (mouse.y * 0.5 - camera.position.y) * 0.05;
      camera.lookAt(scene.position);

      renderer.render(scene, camera);
      requestAnimationFrame(animate);
    };
    animate();

    // Cleanup
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      geometry.dispose();
      material.dispose();
      cardGeo.dispose();
      cardMat.dispose();
      scene.clear();
      if (container.contains(renderer.domElement)) {
        container.removeChild(renderer.domElement);
      }
    };
  }, [color1, color2, cardParams]);

  return (
    <div
      ref={mountRef}
      role="region"
      aria-label="Interactive 3D aurora background"
      className="w-full h-full pointer-events-none"
    />
  );
};

export default ThreeScene;
